var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"꼴사납게 덜렁거리던 목이 드디어 떨어졌구나.","JPN":"無様に揺れていた首がようやく地に落ちたな。","ENG":"So that ugly, dangling head finally came off.","TWN":"那狼狽地搖晃著的頭，終於掉下來了。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"바닥을 나뒹구는 기분은 어떠냐?","JPN":"地面を転がる気分はどうだ？","ENG":"How does it feel, rolling across the dirt like that?","TWN":"在地上滾動的感覺如何？"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"…성급히 으스댈 것 없다.","JPN":"……調子に乗るでない。","ENG":"…Don't be so quick to gloat.","TWN":"…別急著炫耀。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"옛적에 갇혀 있던 때와 달리- 지금 본좌에겐 존자로 군림할 힘이 충만함이라.","JPN":"過去に閉じ込められていたかつてと違い、今の吾輩は天に君臨する力がみなぎっている。","ENG":"No longer bound as I once was, I now possess power overflowing, enough to rule as a revered sovereign!","TWN":"與從前被囚禁時不同—現在本座充滿了君臨萬物的力量。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"현세의 인간들이 흘린 피와 한이 제물 되어 이 몸은 몇 번이고 고쳐 일어설 것이다.","JPN":"現世の人間が流した血と怨念が生贄となり、吾輩は何度でも立ち上がるだろう。","ENG":"The blood and resentment of mankind in this age have become my offering. With it, I will rise again and again.","TWN":"現世的人類流下的鮮血和怨恨將成為祭品，我的身體會一次又一次地重新站起來。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"범의 목에서… 머리가 다시 자라고 있어요.","JPN":"虎の首から……頭が生えてきます。","ENG":"The Tiger's head… it's growing back from the neck.","TWN":"老虎的脖子…頭又長出來了。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"참으로 흉물이군. 떨어진 머리는 붙일 필요도 없다는 건가.","JPN":"実に禍々しい光景だな。落とされた頭をつける必要もないということか。","ENG":"What a monstrosity. So it doesn't even need the severed one reattached.","TWN":"真是個不祥的東西。掉了的頭也不需要再接上嗎？"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"허나, 한 번 죽은 녀석을 되살아나게 둘 생각은 없다.","JPN":"だが、一度死んだやつを蘇らせるつもりはない。","ENG":"Still, I won't let that thing rise again.","TWN":"但是，我可不打算讓已經死過一次的傢伙復活。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"소용없는 짓이다.","JPN":"無駄だ。","ENG":"A wasted effort.","TWN":"這是徒勞的。"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"이 몸에 깃든 힘은 그 어느 때보다 넘치고 있으니…","JPN":"この体に宿る力はいつになく溢れて……","ENG":"I hold more power than ever…","TWN":"這具身體裡蘊含的力量，比任何時候都要充沛…"},"stage":{"bg":"BLACKMOUNTAIN_3","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"…무어냐?","JPN":"……何だ？","ENG":"…What is this?","TWN":"…什麼？"},"stage":{"bg":"BLACKMOUNTAIN_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"어찌하여 이 몸의 수복이 이토록 더딘 것이지?","JPN":"なぜ体の修復が遅れている？","ENG":"Why is my recovery slowing?","TWN":"為什麼這具身體的修復如此緩慢？"},"stage":{"bg":"BLACKMOUNTAIN_2","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"네놈이 둑에 물을 채웠다고 해서 그 물의 영원한 주인이란 뜻은 아니지.","JPN":"貴様が堤に水を満たしたからといって、いつまでもその水の主になるわけではないからだ。","ENG":"Just because you filled a dam with water doesn't mean you're its eternal master.","TWN":"你以為只要築起了水壩，那水就永遠屬於你嗎？"},"stage":{"bg":"BLACKMOUNTAIN_2","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"둑이 무너지면, 고여있던 물은 그저 섭리를 따라 아래로 흘러갈 뿐.","JPN":"堤が崩れれば、溜まっていた水は下へと流れるのが世の摂理。","ENG":"When a dam breaks, the stagnant water simply follows its nature and flows downward.","TWN":"水壩一旦崩塌，積聚的水只會順著道理流向下方。"},"stage":{"bg":"BLACKMOUNTAIN_2","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"네놈… 무슨 뜻 모를 허언을 지껄이는 것이냐?","JPN":"貴様……何訳の分からんことをほざいている？","ENG":"You… speak nonsense. What are you babbling about?","TWN":"你這傢伙…在說什麼莫名其妙的廢話？"},"stage":{"bg":"BLACKMOUNTAIN_2","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"간단한 얘기다.","JPN":"簡単な話だ。","ENG":"It's simple.","TWN":"很簡單。"},"stage":{"bg":"BLACKMOUNTAIN_2","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"목이 잘린 네 놈에겐 그 많은 힘을 붙잡아둘 여력이 없으니, 쏟아진 힘이 그 아래의 마땅한 주인을 찾아갔다는 뜻이다.","JPN":"首が斬られたお前には、莫大な力を抑え込めるだけの余力がない。そうやって溢れ出た力が、その下の然るべき主へと行き着いたというわけだ。","ENG":"With your neck severed, you had no strength left to contain all that power. That is why the spilled power simply went to find its rightful owner below.","TWN":"頭被砍下的你，沒有能力抓住那麼龐大的力量，所以湧出的力量，找到了下一個應有的主人。"},"stage":{"bg":"BLACKMOUNTAIN_2","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"narration","speaker":null,"text":{"KOREA":"마땅한 주인이라?","JPN":"然るべき主？","ENG":"Rightful owner?","TWN":"應有的主人？"},"stage":{"bg":"BLACKMOUNTAIN_2","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"narration","speaker":null,"text":{"KOREA":"본좌와 같은 힘을 쓰는 존재가 달리 있을 리…","JPN":"吾輩と同類の力を振るう存在など、他にいるはずが……","ENG":"There can be no other being with this power but m–","TWN":"除了本座之外，還有誰能使用同樣的力量…"},"stage":{"bg":"BLACKMOUNTAIN_2","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"narration","speaker":null,"text":{"KOREA":"…설마?","JPN":"……まさか？","ENG":"…It can't be!","TWN":"…難道是？"},"stage":{"bg":"BLACKMOUNTAIN_2","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"……","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACKMOUNTAIN_2","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"서생…!","JPN":"ショウ……！","ENG":"Seosaeng…!","TWN":"書生…！"},"stage":{"bg":"BLACKMOUNTAIN_2","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"네놈이… 어떻게 아직도…?","JPN":"貴様……なぜまだ……？","ENG":"How… are you still alive…?","TWN":"你這傢伙…怎麼還…？"},"stage":{"bg":"BLACKMOUNTAIN_2","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이건… 환 같은 건가?","JPN":"これは……丸薬か？","ENG":"Is this… some kind of pill?","TWN":"這是… 幻覺藥嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"일회용 각성제라고 생각하게나.","JPN":"使い捨ての覚醒剤だと思ってくれ。","ENG":"It is called Deathward. Think of it as a one-time-use stimulant.","TWN":"這是名為續命術的藥。把它當成一次性的覺醒劑吧。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};